update sysuser
set balance = balance + #{amount}
where id = #{id}

update sysuser
set nickname = #{nickname},
    balance = balance + #{amount}
where id = #{id}

update sysuser
set status = #{status}
where id = #{id}

update sysuser
set password = #{password}
where id = #{id}

update sysuser
set balance = balance - #{amount}
where id = #{id}
  and balance >= #{amount}

update sysuser
set avatar = #{avatar}
where id = #{id}
